function o(e){if(!e)return!1;const t=new Date;return t.setHours(0,0,0,0),new Date(e+"T00:00:00").getTime()<=t.getTime()}function r(e){const t=new Date;t.setHours(0,0,0,0);const a=new Date(e+"T00:00:00").getTime()-t.getTime();return Math.ceil(a/(1e3*60*60*24))}function c(e){return new Date(e+"T00:00:00").toLocaleDateString("it-IT",{day:"numeric",month:"long",year:"numeric"})}function s(e,t="date"){return e.map(n=>({...n,unlocked:o(n[t]),daysUntil:r(n[t])}))}export{c as f,o as i,s as w};
